        &QueryString;

declare @jobName nvarchar(4000), @accountName nvarchar(4000)
if exists(select 1 from dmvv where ma_vv = @ma_vv)
  select @jobName = rtrim(isnull(case when @@language = 'V' then ten_vv else ten_vv2 end, '')) from dmvv where ma_vv = @ma_vv
else
  select @jobName = ''
if exists(select 1 from dmtk where tk = @tk)
  select @accountName = rtrim(isnull(case when @@language = 'V' then ten_tk else ten_tk2 end, '')) from dmtk where tk = @tk
else
  select @accountName = ''
select 'this._jobName = ''' + replace(replace(@jobName, '\', '\\'), '''', '\''') + ''';this._accountName = ''' + replace(replace(@accountName, '\', '\\'), '''', '\''') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmkh b on a.ma_kh = b.ma_kh'
select @queryWhereClause = 'a.ma_vv like ''' +  replace(@ma_vv, '''', '''''') + ''''
if @so_ct1 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct >= ''' + dbo.ff_PadL(replace(rtrim(@so_ct1), '''', ''''''), @maxLength) + ''''
if @so_ct2 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct <= ''' + dbo.ff_PadL(replace(rtrim(@so_ct2), '''', ''''''), @maxLength) + ''''
if @tk <> '' select @queryWhereClause = @queryWhereClause + ' and a.tk = ''' + replace(@tk, '''', '''''') + ''''
if @ds_tk_du <> '' select @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'inlist', @ds_tk_du)
select @queryWhereClause = @queryWhereClause +
  case
    when @ghi_no_co = 1 then ' and (a.ps_no + a.ps_no_nt <> 0' + case when @ds_tk_gt = '' then ')' else ' or (a.ps_co + a.ps_co_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk_gt) + '))' end
    when @ghi_no_co = 2 then ' and (a.ps_co + a.ps_co_nt <> 0' + case when @ds_tk_gt = '' then ')' else ' or (a.ps_no + a.ps_no_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk_gt) + '))' end
  end
if @vv_me <> '' select @queryWhereClause = @queryWhereClause + ' and (dbo.ff_IsRelationJob(''' + replace(rtrim(@vv_me), '''', '''''') + ''', a.ma_vv) = 1)'
if @ma_kh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'''
if @ma_ct <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_ct like ''' + replace(rtrim(@ma_ct), '''', '''''') + '%'''
if @ma_nt <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nt like ''' + replace(rtrim(@ma_nt), '''', '''''') + '%'''
if @dien_giai <> '' select @queryWhereClause = @queryWhereClause + ' and a.dien_giai like N''%' + replace(rtrim(@dien_giai), '''', '''''') + '%'''

&FilterInitialize;&FilterQuery;
exec FastBusiness$Report$GLDetail @@refresh, @@pageIndex, @@pageCount, @@lastPage, @@lastCount, @@firstItem, @@lastItem,
  @@textExternal, @queryFormClause, @queryWhereClause, @ngay_ct1, @ngay_ct2, @ma_dvcs, @@admin, @@userID, @@aggregation







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[1], true], ['%s', g._jobName, true], ['%k', a[0], true], ['%m', g._accountName, true], ['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
  var y = a[17];
  g._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt', Value: (y == '10')}];
}
/* </flatten> */



